import React, { useState } from 'react';
import StatCard from './StatCard';
import { 
  Calendar, 
  TrendingUp, 
  CheckCircle2, 
  Clock, 
  Search, 
  AlertCircle, 
  Activity,
  ShieldAlert
} from 'lucide-react';

const STAGES = [
  { id: 'design', label: 'Design', statuses: ['Design', 'Awaiting Artwork', 'Artwork Uploaded'] },
  { id: 'digitizer', label: 'Digitizer', statuses: ['Digitizing', 'Awaiting Digitizing', 'Digitized'] },
  { id: 'billing', label: 'Billing', statuses: ['Billing', 'Awaiting Invoice', 'Awaiting Payment', 'Paid'] },
  { id: 'om', label: 'OM Review', statuses: ['Order Management'] },
  { id: 'production', label: 'Production', statuses: ['Production'] },
  { id: 'delivery', label: 'Delivery', statuses: ['Delivery'] },
  { id: 'completed', label: 'Completed', statuses: ['Completed'] }
];

const getActiveStageIndex = (status) => {
  const normalizedStatus = (status || '').trim();
  const index = STAGES.findIndex(s => s.statuses.includes(normalizedStatus) || s.id === normalizedStatus.toLowerCase());
  if (index !== -1) return index;
  
  // Spelled matches & sub-substrings
  if (normalizedStatus.includes('Design')) return 0;
  if (normalizedStatus.includes('Digitiz')) return 1;
  if (normalizedStatus.includes('Bill') || normalizedStatus.includes('Invoice') || normalizedStatus.includes('Payment') || normalizedStatus.includes('Paid')) return 2;
  if (normalizedStatus.includes('Management') || normalizedStatus === 'OM') return 3;
  if (normalizedStatus.includes('Production')) return 4;
  if (normalizedStatus.includes('Delivery')) return 5;
  if (normalizedStatus.includes('Completed')) return 6;
  return 0;
};

const Pipeline = ({ currentStatus }) => {
  const activeIdx = getActiveStageIndex(currentStatus);
  return (
    <div style={{ 
      display: 'flex', 
      alignItems: 'center', 
      gap: '4px', 
      background: 'rgba(255,255,255,0.02)', 
      padding: '4px 8px', 
      borderRadius: '6px', 
      border: '1px solid rgba(255,255,255,0.05)', 
      width: 'fit-content' 
    }}>
      {STAGES.map((stage, idx) => {
        const isCompleted = idx < activeIdx;
        const isActive = idx === activeIdx;
        let color = 'rgba(255, 255, 255, 0.25)'; // muted grey
        if (isActive) {
          color = '#d946ef'; // active design purple/pink
        } else if (isCompleted) {
          color = '#10b981'; // completed green
        }
        return (
          <React.Fragment key={stage.id}>
            {idx > 0 && <span style={{ color: 'rgba(255,255,255,0.1)', fontSize: '0.65rem', userSelect: 'none' }}>➔</span>}
            <span style={{
              fontSize: '0.68rem',
              fontWeight: isActive ? 800 : 500,
              color: color,
              background: isActive ? 'rgba(217, 70, 239, 0.08)' : 'transparent',
              padding: isActive ? '2px 5px' : '0',
              borderRadius: '4px',
              border: isActive ? '1px solid rgba(217, 70, 239, 0.2)' : 'none',
              cursor: 'default'
            }}>
              {stage.label}
            </span>
          </React.Fragment>
        );
      })}
    </div>
  );
};

const GlobalDashboardOverview = ({ orders, themeColor = 'admin' }) => {
  const [search, setSearch] = useState('');
  const [dateFilter, setDateFilter] = useState('all'); // 'all' | 'today' | 'week' | 'month'

  // ── Date-based KPI statistics ─────────────────────────────
  const getOrderStats = () => {
    // Standard system clock reference is June 23, 2026
    const today = new Date();
    today.setHours(0, 0, 0, 0);

    // Week start (Sunday)
    const sunday = new Date(today);
    sunday.setDate(today.getDate() - today.getDay());
    sunday.setHours(0, 0, 0, 0);

    // Month start (1st day)
    const firstOfMonth = new Date(today.getFullYear(), today.getMonth(), 1);

    let todayCount = 0;
    let weekCount = 0;
    let monthCount = 0;
    let completedCount = 0;
    let processCount = 0;
    let holdCount = 0;

    (orders || []).forEach(o => {
      // Priority statuses
      if (o.is_hold === 1) {
        holdCount++;
      } else if (o.status === 'Completed') {
        completedCount++;
      } else {
        processCount++;
      }

      // Date aggregates
      if (o.orderDate) {
        const parts = o.orderDate.split('-');
        if (parts.length === 3) {
          const oDate = new Date(parts[0], parts[1] - 1, parts[2]);
          oDate.setHours(0, 0, 0, 0);

          if (oDate.getTime() === today.getTime()) {
            todayCount++;
          }
          if (oDate >= sunday && oDate <= today) {
            weekCount++;
          }
          if (oDate >= firstOfMonth && oDate <= today) {
            monthCount++;
          }
        }
      }
    });

    return { todayCount, weekCount, monthCount, completedCount, processCount, holdCount };
  };

  const stats = getOrderStats();

  // ── Search & Filter ──────────────────────────────────────
  const filteredOrders = (orders || []).filter(o => {
    const term = search.toLowerCase();
    const matchesSearch = (
      String(o.id).toLowerCase().includes(term) ||
      (o.clientName || '').toLowerCase().includes(term) ||
      (o.items || '').toLowerCase().includes(term) ||
      (o.status || '').toLowerCase().includes(term)
    );
    if (!matchesSearch) return false;

    if (dateFilter === 'all') return true;

    const today = new Date();
    today.setHours(0, 0, 0, 0);

    const sunday = new Date(today);
    sunday.setDate(today.getDate() - today.getDay());
    sunday.setHours(0, 0, 0, 0);

    const firstOfMonth = new Date(today.getFullYear(), today.getMonth(), 1);

    if (o.orderDate) {
      const parts = o.orderDate.split('-');
      if (parts.length === 3) {
        const oDate = new Date(parts[0], parts[1] - 1, parts[2]);
        oDate.setHours(0, 0, 0, 0);

        if (dateFilter === 'today') {
          return oDate.getTime() === today.getTime();
        }
        if (dateFilter === 'week') {
          return oDate >= sunday && oDate <= today;
        }
        if (dateFilter === 'month') {
          return oDate >= firstOfMonth && oDate <= today;
        }
      }
    }
    return false;
  });

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: '24px' }}>
      {/* ── KPI Stat Cards ── */}
      <div style={{ 
        display: 'grid', 
        gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', 
        gap: '16px' 
      }}>
        <StatCard title="Total Completed" value={stats.completedCount} subtext="Delivered & settled" icon={CheckCircle2} color="account" />
        <StatCard title="Total In-Process" value={stats.processCount} subtext="Currently moving" icon={Activity} color="design" />
        <StatCard title="Total On Hold" value={stats.holdCount} subtext="Paused pipelines" icon={ShieldAlert} color="order" />
      </div>
    </div>
  );
};

export default GlobalDashboardOverview;
