import React from 'react';
import { TrendingUp, Users, MoreVertical } from 'lucide-react';

const SalesPerformanceAndBreakdown = () => {
  // Chart coordinates calculation
  // Let's draw a beautiful SVG Spline line chart for Sales Performance
  // values: Jan (30k), Feb (45k), Mar (35k), Apr (60k), May (50k), Jun (75k)
  const salesData = [30, 45, 35, 60, 50, 75];
  const months = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun'];

  const width = 460;
  const height = 180;
  const padding = 30;

  const getX = (index) => padding + (index * (width - 2 * padding)) / (salesData.length - 1);
  const getY = (val) => height - padding - ((val - 20) * (height - 2 * padding)) / 60; // range 20k to 80k

  // Generate path points
  const points = salesData.map((val, idx) => ({ x: getX(idx), y: getY(val) }));
  
  // Create smooth Bezier spline path
  let linePath = '';
  let areaPath = `M ${points[0].x} ${height - padding}`;
  
  if (points.length > 0) {
    linePath = `M ${points[0].x} ${points[0].y}`;
    areaPath += ` L ${points[0].x} ${points[0].y}`;
    
    for (let i = 0; i < points.length - 1; i++) {
      const p0 = points[i];
      const p1 = points[i + 1];
      const cpX1 = p0.x + (p1.x - p0.x) / 2;
      const cpY1 = p0.y;
      const cpX2 = p0.x + (p1.x - p0.x) / 2;
      const cpY2 = p1.y;
      
      linePath += ` C ${cpX1} ${cpY1}, ${cpX2} ${cpY2}, ${p1.x} ${p1.y}`;
      areaPath += ` C ${cpX1} ${cpY1}, ${cpX2} ${cpY2}, ${p1.x} ${p1.y}`;
    }
    areaPath += ` L ${points[points.length - 1].x} ${height - padding} Z`;
  }

  return (
    <div style={{
      display: 'grid',
      gridTemplateColumns: 'repeat(auto-fit, minmax(380px, 1fr))',
      gap: '24px',
      width: '100%',
      boxSizing: 'border-box'
    }}>
      {/* Sales Performance Spline Chart */}
      <div className="glass-panel" style={{
        padding: '24px',
        background: 'var(--bg-card)',
        borderRadius: '16px',
        border: '1px solid var(--border-color)',
        display: 'flex',
        flexDirection: 'column',
        boxShadow: '0 1px 3px rgba(0,0,0,0.05)'
      }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '16px' }}>
          <div>
            <h3 style={{ fontSize: '0.95rem', fontWeight: 800, color: 'var(--text-primary)', margin: 0, display: 'flex', alignItems: 'center', gap: '6px' }}>
              <TrendingUp size={16} style={{ color: 'var(--color-primary)' }} />
              Sales Performance
            </h3>
            <span style={{ fontSize: '0.72rem', color: 'var(--text-secondary)' }}>Monthly transaction values</span>
          </div>
          <span style={{ fontSize: '0.72rem', color: '#10b981', background: 'rgba(16, 185, 129, 0.1)', padding: '4px 8px', borderRadius: '6px', fontWeight: 700 }}>
            +24% Growth
          </span>
        </div>

        <div style={{ position: 'relative', width: '100%', flex: 1, minHeight: '180px' }}>
          <svg viewBox={`0 0 ${width} ${height}`} width="100%" height="100%" style={{ overflow: 'visible' }}>
            <defs>
              <linearGradient id="salesAreaGrad" x1="0" y1="0" x2="0" y2="1">
                <stop offset="0%" stopColor="var(--color-primary)" stopOpacity="0.25" />
                <stop offset="100%" stopColor="var(--color-primary)" stopOpacity="0.0" />
              </linearGradient>
            </defs>

            {/* Gridlines */}
            {[20, 40, 60, 80].map((val) => (
              <g key={val}>
                <line
                  x1={padding}
                  y1={getY(val)}
                  x2={width - padding}
                  y2={getY(val)}
                  stroke="var(--border-color)"
                  strokeWidth="0.8"
                  strokeDasharray="4 4"
                />
                <text
                  x={padding - 6}
                  y={getY(val) + 3}
                  fill="var(--text-secondary)"
                  fontSize="8"
                  fontWeight="600"
                  textAnchor="end"
                >
                  ${val}k
                </text>
              </g>
            ))}

            {/* Area under spline */}
            <path d={areaPath} fill="url(#salesAreaGrad)" />

            {/* Spline line path */}
            <path
              d={linePath}
              fill="none"
              stroke="var(--color-primary)"
              strokeWidth="2.5"
              strokeLinecap="round"
            />

            {/* Month labels */}
            {months.map((m, idx) => (
              <text
                key={m}
                x={getX(idx)}
                y={height - 8}
                fill="var(--text-secondary)"
                fontSize="8"
                fontWeight="700"
                textAnchor="middle"
              >
                {m}
              </text>
            ))}

            {/* Nodes/Dots on peak values */}
            {points.map((pt, idx) => (
              <circle
                key={idx}
                cx={pt.x}
                cy={pt.y}
                r="4"
                fill="var(--bg-card)"
                stroke="var(--color-primary)"
                strokeWidth="2"
              />
            ))}
          </svg>
        </div>
      </div>

      {/* Customer Segment Breakdown Donut Chart */}
      <div className="glass-panel" style={{
        padding: '24px',
        background: 'var(--bg-card)',
        borderRadius: '16px',
        border: '1px solid var(--border-color)',
        display: 'flex',
        flexDirection: 'column',
        boxShadow: '0 1px 3px rgba(0,0,0,0.05)'
      }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '16px' }}>
          <div>
            <h3 style={{ fontSize: '0.95rem', fontWeight: 800, color: 'var(--text-primary)', margin: 0, display: 'flex', alignItems: 'center', gap: '6px' }}>
              <Users size={16} style={{ color: '#10b981' }} />
              Customer Segments
            </h3>
            <span style={{ fontSize: '0.72rem', color: 'var(--text-secondary)' }}>Distribution of active client profiles</span>
          </div>
          <MoreVertical size={16} style={{ color: 'var(--text-muted)', cursor: 'pointer' }} />
        </div>

        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '28px', flex: 1, minHeight: '150px' }}>
          {/* Donut circle SVG */}
          <div style={{ position: 'relative', width: '110px', height: '110px' }}>
            <svg width="110" height="110" viewBox="0 0 36 36" style={{ transform: 'rotate(-90deg)', width: '100%', height: '100%' }}>
              <circle cx="18" cy="18" r="15.915" fill="none" stroke="var(--border-color)" strokeWidth="3" />
              
              {/* Segment 1: Repeat (40%) - blue */}
              <circle cx="18" cy="18" r="15.915" fill="none" stroke="#3b82f6" strokeWidth="3" strokeDasharray="40 100" strokeDashoffset="0" />
              
              {/* Segment 2: New (45%) - green */}
              <circle cx="18" cy="18" r="15.915" fill="none" stroke="#10b981" strokeWidth="3" strokeDasharray="45 100" strokeDashoffset="-40" />
              
              {/* Segment 3: VIP (15%) - yellow */}
              <circle cx="18" cy="18" r="15.915" fill="none" stroke="#f59e0b" strokeWidth="3" strokeDasharray="15 100" strokeDashoffset="-85" />
            </svg>
            <div style={{
              position: 'absolute', top: 0, left: 0, right: 0, bottom: 0,
              display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center',
              fontSize: '0.6rem', fontWeight: 800, textTransform: 'uppercase', color: 'var(--text-secondary)',
              textAlign: 'center', pointerEvents: 'none', lineHeight: '1.2'
            }}>
              Active<br/>Clients
            </div>
          </div>

          {/* Legend */}
          <div style={{ display: 'flex', flexDirection: 'column', gap: '8px', fontSize: '0.75rem', flex: 1 }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
                <span style={{ width: '8px', height: '8px', borderRadius: '50%', background: '#3b82f6' }}></span>
                <span style={{ fontWeight: 600, color: 'var(--text-secondary)' }}>Repeat Clients</span>
              </div>
              <span style={{ fontWeight: 800, color: 'var(--text-primary)' }}>40%</span>
            </div>

            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
                <span style={{ width: '8px', height: '8px', borderRadius: '50%', background: '#10b981' }}></span>
                <span style={{ fontWeight: 600, color: 'var(--text-secondary)' }}>New Leads</span>
              </div>
              <span style={{ fontWeight: 800, color: 'var(--text-primary)' }}>45%</span>
            </div>

            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
                <span style={{ width: '8px', height: '8px', borderRadius: '50%', background: '#f59e0b' }}></span>
                <span style={{ fontWeight: 600, color: 'var(--text-secondary)' }}>VIP Accounts</span>
              </div>
              <span style={{ fontWeight: 800, color: 'var(--text-primary)' }}>15%</span>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default SalesPerformanceAndBreakdown;
