    8:  { title: 'Acme Group Uniform Consultation', type: 'Call', desc: 'Discuss custom embroidered chef aprons mockup details.' },
    15: { title: 'Bulk Email Campaign blast', type: 'Email', desc: 'Newsletter distribution to 5,000 corporate clients with Summer merch discount codes.' },
